import{R as t,e as r,f as a,U as i}from"./chunks/framework.3syO9N_q.js";const g=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/overview.md","filePath":"getting-started/overview.md","lastUpdated":1777089442000}'),o={name:"getting-started/overview.md"};function n(l,e,s,d,h,c){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p><code>@verbb/plugin-kit-react</code> is for Craft plugin developers who want to build richer control panel interfaces with React instead of only Twig and server-rendered HTML.</p><p>The main job of this package is to help you get a React app running inside the Craft control panel without having to solve all the UI, styling, and host-integration pieces from scratch.</p><h2 id="what-this-package-gives-you" tabindex="-1">What this package gives you <a class="header-anchor" href="#what-this-package-gives-you" aria-label="Permalink to &quot;What this package gives you&quot;">​</a></h2><ul><li>React components that feel at home in the Craft control panel</li><li>Helpers for connecting your React app to Craft concepts such as translations, dialogs, portals, and host APIs</li><li>Styling support for both normal DOM rendering and Shadow DOM rendering</li><li>Form-building tools for more advanced, Craft-like interfaces once your app is running</li></ul><h2 id="built-with" tabindex="-1">Built with <a class="header-anchor" href="#built-with" aria-label="Permalink to &quot;Built with&quot;">​</a></h2><p>These libraries are part of the shipped UI and form stack (bundled as dependencies of <code>@verbb/plugin-kit-react</code>). You do not have to install them separately unless your plugin imports them directly alongside the kit.</p><ul><li><strong><a href="https://base-ui.com/react" target="_blank" rel="noreferrer">Base UI</a></strong> (<code>@base-ui/react</code>) — headless, accessible primitives for dialogs, menus, popovers, and similar patterns</li><li><strong><a href="https://tailwindcss.com/" target="_blank" rel="noreferrer">Tailwind CSS</a></strong> v4 — utility-first styling behind <code>@verbb/plugin-kit-react/style.css</code>, with helpers such as <a href="https://github.com/dcastil/tailwind-merge" target="_blank" rel="noreferrer"><code>tailwind-merge</code></a>, <a href="https://github.com/lukeed/clsx" target="_blank" rel="noreferrer"><code>clsx</code></a>, and <a href="https://cva.style/docs" target="_blank" rel="noreferrer"><code>class-variance-authority</code></a></li><li><strong><a href="https://react.dev/" target="_blank" rel="noreferrer">React</a></strong> 19 — peer dependency; the kit targets the same major as Craft’s CP React stack</li><li><strong><a href="https://github.com/pmndrs/zustand" target="_blank" rel="noreferrer">Zustand</a></strong> — SchemaForm engine state</li><li><strong><a href="https://valibot.dev/" target="_blank" rel="noreferrer">Valibot</a></strong> — schema validation for forms</li><li><strong><a href="https://github.com/TomFischer/jexl" target="_blank" rel="noreferrer">Jexl</a></strong> — condition expressions in schema-driven forms</li><li><strong><a href="https://tiptap.dev/" target="_blank" rel="noreferrer">TipTap</a></strong> / <strong><a href="https://prosemirror.net/" target="_blank" rel="noreferrer">ProseMirror</a></strong> — rich text editing (<code>TiptapEditor</code>, <code>TiptapInput</code>, and related schema fields)</li><li><strong><a href="https://motion.dev/" target="_blank" rel="noreferrer">Framer Motion</a></strong> — motion and layout transitions where components use it</li><li><strong><a href="https://dndkit.dev/" target="_blank" rel="noreferrer">@dnd-kit</a></strong> — drag-and-drop for sortable or builder-style surfaces</li><li><strong><a href="https://cmdk.paco.me/" target="_blank" rel="noreferrer">cmdk</a></strong> — command-palette style UI (for example variable picker flows)</li><li><strong><a href="https://tanstack.com/virtual" target="_blank" rel="noreferrer">@tanstack/react-virtual</a></strong> — virtualized lists in heavy menus or tables</li><li><strong><a href="https://react-day-picker.js.org/" target="_blank" rel="noreferrer">react-day-picker</a></strong> — calendar and date picking</li><li><strong><a href="https://fontawesome.com/" target="_blank" rel="noreferrer">Font Awesome</a></strong> — icons via <code>@fortawesome/react-fontawesome</code> and Pro icon sets bundled for kit components</li></ul><h2 id="what-you-will-build-in-this-guide" tabindex="-1">What you will build in this guide <a class="header-anchor" href="#what-you-will-build-in-this-guide" aria-label="Permalink to &quot;What you will build in this guide&quot;">​</a></h2><p>The getting started path assumes you are starting from a PHP-only plugin with no frontend build setup yet.</p><p>By the end of it, you should understand how to:</p><ol><li>add a small frontend toolchain to your plugin</li><li>create a React entry file</li><li>register the built files as a Craft CP asset bundle</li><li>render a mount element in your template or CP page</li><li>mount your first <code>plugin-kit-react</code> UI inside the Craft control panel</li></ol><h2 id="where-to-read-next" tabindex="-1">Where to read next <a class="header-anchor" href="#where-to-read-next" aria-label="Permalink to &quot;Where to read next&quot;">​</a></h2><ol><li>Read <a href="./quick-start">Quick Start</a> for the full PHP-plugin-to-first-React-screen setup.</li><li>Read <a href="./css-setup">CSS setup</a> once your app is mounting and you are ready to choose light DOM or Shadow DOM.</li><li>Read <a href="./testing-and-debugging">Testing and debugging</a> if your first integration is not behaving as expected.</li><li>Read <a href="./../react-app/creating-a-react-app">Creating a React app</a> when you want the frontend concepts explained in more detail, then use the React app reference pages as needed.</li></ol>',14)])])}const u=t(o,[["render",n]]);export{g as __pageData,u as default};
